@namespace Lumeo

@{
    var context = new SheetContext(Open, EventCallback.Factory.Create<bool>(this, SetOpen), _titleId, _descriptionId);
}

<CascadingValue Value="context" IsFixed="false">
    @ChildContent
</CascadingValue>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public bool Open { get; set; }
    [Parameter] public EventCallback<bool> OpenChanged { get; set; }

    [Obsolete("Use Open instead. IsOpen will be removed in a future release.")]
    [Parameter] public bool IsOpen { get => Open; set => Open = value; }

    [Obsolete("Use OpenChanged instead. IsOpenChanged will be removed in a future release.")]
    [Parameter] public EventCallback<bool> IsOpenChanged { get => OpenChanged; set => OpenChanged = value; }

    private readonly string _titleId = $"sheet-title-{Guid.NewGuid():N}";
    private readonly string _descriptionId = $"sheet-desc-{Guid.NewGuid():N}";

    private async Task SetOpen(bool value)
    {
        Open = value;
        await OpenChanged.InvokeAsync(value);
    }

    public record SheetContext(bool IsOpen, EventCallback<bool> SetOpen, string TitleId, string DescriptionId);
}

@namespace Lumeo

<div class="@CssClass" @onclick="Close" @attributes="AdditionalAttributes">
    @ChildContent
</div>

@code {
    [CascadingParameter] public Sheet.SheetContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"inline-flex {Class}".Trim();

    private async Task Close() => await Context.SetOpen.InvokeAsync(false);
}

@namespace Lumeo
@using Lumeo.Services
@implements IAsyncDisposable

@if (Shell is not null)
{
    @* OverlayProvider already rendered the SheetContent shell around our parent
       component — rendering another shell here would stack a second backdrop +
       sliding panel on top. Pass the children straight through to the host
       shell instead. Side / Size / PreventClose / Class on this nested element
       are intentionally ignored; the provider controls those via OverlayOptions. *@
    @ChildContent
}
else if (Context.IsOpen)
{
    <div class="fixed inset-0 z-50">
        <div class="fixed inset-0 bg-black/80 animate-fade-in" @onclick="HandleBackdropClick"></div>
        <div id="@_contentId" class="@CssClass" role="dialog" aria-modal="true" aria-labelledby="@Context.TitleId" aria-describedby="@Context.DescriptionId" @onkeydown="HandleKeyDown" tabindex="-1" @attributes="AdditionalAttributes">
            @ChildContent
            @if (!PreventClose)
            {
                <button class="absolute right-4 top-4 rounded-sm opacity-70 transition-opacity hover:opacity-100 focus:outline-none" @onclick="Close">
                    <Blazicon Svg="Lucide.X" class="h-4 w-4" />
                    <span class="sr-only">@L["Dialog.Close"]</span>
                </button>
            }
        </div>
    </div>
}

@inject ComponentInteropService Interop
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@code {
    [CascadingParameter] public Sheet.SheetContext Context { get; set; } = default!;
    [CascadingParameter] public OverlayShellMarker? Shell { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public SheetSide Side { get; set; } = SheetSide.Right;
    [Parameter] public SheetSize Size { get; set; } = SheetSize.Default;
    [Parameter] public bool PreventClose { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _contentId = $"sheet-{Guid.NewGuid():N}";
    private bool _wasOpen;

    private string CssClass => $"fixed z-50 gap-4 bg-background p-6 shadow-lg {SideClasses} {Class}".Trim();

    private string SizeClass => Side is SheetSide.Left or SheetSide.Right
        ? Size switch
        {
            SheetSize.Sm => "sm:max-w-xs",
            SheetSize.Lg => "sm:max-w-lg",
            SheetSize.Xl => "sm:max-w-xl",
            SheetSize.Full => "sm:max-w-full",
            _ => "sm:max-w-sm"
        }
        : "";

    private string SideClasses => Side switch
    {
        SheetSide.Top => "inset-x-0 top-0 animate-slide-in-from-top",
        SheetSide.Bottom => "inset-x-0 bottom-0 animate-slide-in-from-bottom",
        SheetSide.Left => $"inset-y-0 left-0 h-full w-3/4 {SizeClass} animate-slide-in-from-left",
        SheetSide.Right => $"inset-y-0 right-0 h-full w-3/4 {SizeClass} animate-slide-in-from-right",
        _ => $"inset-y-0 right-0 h-full w-3/4 {SizeClass} animate-slide-in-from-right"
    };

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        // When passthrough mode is active the host SheetContent owns scroll lock
        // + focus trap; this nested instance is a no-op for lifecycle effects.
        if (Shell is not null) return;

        if (Context.IsOpen && !_wasOpen)
        {
            await Interop.LockScroll();
            await Interop.SetupFocusTrap(_contentId);
            _wasOpen = true;
        }
        else if (!Context.IsOpen && _wasOpen)
        {
            await Cleanup();
            _wasOpen = false;
        }
    }

    private async Task Close() => await Context.SetOpen.InvokeAsync(false);

    private async Task HandleBackdropClick()
    {
        if (!PreventClose) await Close();
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Escape" && !PreventClose) await Close();
    }

    private async Task Cleanup()
    {
        try
        {
            await Interop.RemoveFocusTrap(_contentId);
            await Interop.UnlockScroll();
        }
        catch (JSDisconnectedException) { }
    }

    public async ValueTask DisposeAsync()
    {
        if (_wasOpen) await Cleanup();
    }

    public enum SheetSide { Top, Right, Bottom, Left }
    public enum SheetSize { Sm, Default, Lg, Xl, Full }
}

